const e={configTemplates:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Bloques de configuración y macros de Klipper listos para pegar — secuencias de inicio, manejo de filamento, input shaping, malla de cama y más. Copia uno y pégalo en tu printer.cfg (el Editor de configuración es un buen lugar para pegarlo)."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Ayuda"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Acerca de las plantillas de configuración"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Cerrar"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Cómo usar"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Filtra por categoría para encontrar una macro o un bloque de configuración."}},{t:0,b:{t:2,i:[{t:3}],s:"Lee la descripción y qué secciones necesita."}},{t:0,b:{t:2,i:[{t:3}],s:"Copia la plantilla, pégala en tu configuración y ajusta los valores."}}],topics:{what:{title:{t:0,b:{t:2,i:[{t:3}],s:"Qué son estas plantillas"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un conjunto curado de bloques de construcción comunes de Klipper: gcode_macros (PRINT_START, PAUSE/RESUME, carga/descarga de filamento, M600) y secciones de configuración ([input_shaper], [bed_mesh], [firmware_retraction], …). Son puntos de partida: lee cada uno y ajústalo para tu máquina."}}},insert:{title:{t:0,b:{t:2,i:[{t:3}],s:"Insertar una plantilla"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Copia una plantilla y luego pégala en tu printer.cfg — la vista Raw del Editor de configuración es un lugar conveniente. Tras guardar, un reinicio del firmware la aplica. Revisa siempre los valores primero; los predeterminados aquí son razonables pero no están ajustados a tu impresora."}}},sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Secciones requeridas"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Cada plantilla enumera las secciones de configuración que define o de las que depende. Si una sección ya existe en tu configuración, fusiona las claves en lugar de pegar un duplicado (una sección duplicada se rechaza al arrancar)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glosario"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{template:{term:{t:0,b:{t:2,i:[{t:3}],s:"Plantilla"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un fragmento listo para pegar de configuración de Klipper o de G-code de macro que copias en printer.cfg."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"gcode_macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un comando con nombre que defines en la configuración (p. ej. PRINT_START) que ejecuta una secuencia de G-code."}}},section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Sección"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bloque de configuración [entre corchetes], p. ej. [bed_mesh] — la unidad en la que se agrupa la configuración de Klipper."}}}}},category:{label:{t:0,b:{t:2,i:[{t:3}],s:"Categoría"}},all:{t:0,b:{t:2,i:[{t:3}],s:"Todas las categorías"}}},template:{copy:{t:0,b:{t:2,i:[{t:3}],s:"Copiar"}},copied:{t:0,b:{t:2,i:[{t:3}],s:"¡Copiado!"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Secciones: "},{t:4,k:"sections"}]}},requiresNone:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" plantillas"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Cargando plantillas…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"No se pudieron cargar las plantillas."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"No hay plantillas en esta categoría."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Reintentar"}}},categories:{config_blocks:{t:0,b:{t:2,i:[{t:3}],s:"Bloques de config"}},macros:{t:0,b:{t:2,i:[{t:3}],s:"Macros"}}}}};export{e as default};
